// Filter for scheduled posts that haven't been published
const files = $input.all();
const scheduledFiles = files.filter(file => {
  // Check if it's a post file (.md)
  if (!file.name.endsWith('.md')) return false;

  // Check if file is in posts directory
  if (!file.path.includes('posts/')) return false;

  return true;
});

return scheduledFiles.map(file => ({ json: file }));

// Parse markdown frontmatter and extract content
const content = $input.first().binary.data.toString('utf8');

// Extract frontmatter (between ---)
const frontmatterMatch = content.match(/^---\n(.*?)\n---/s);
if (!frontmatterMatch) {
  return [{ json: { error: 'No frontmatter found' } }];
}

const metadata = frontmatterMatch[1];
const body = content.slice(frontmatterMatch[0].length);

// Parse YAML-like frontmatter
const lines = metadata.split('\n');
const data = {};
let inArray = false;
let currentArray = [];

for (const line of lines) {
  if (line.match(/^(title|type|status|scheduled_date|scheduled_time):/)) {
    const [key, value] = line.split(':').map(s => s.trim().replace(/^"|"$/g, ''));
    data[key] = value;
  } else if (line.match(/^cross_post_to:/)) {
    inArray = true;
  } else if (line.match(/^\]/) {
    inArray = false;
  } else if (inArray && line.trim()) {
    currentArray.push(line.trim().replace(/"/g, ''));
  }
}

data.cross_post_to = currentArray;

// Extract LinkedIn content
const linkedinMatch = body.match(/## LinkedIn\n([\s\S]*?)(?=(##|$)/s);
data.linkedin_content = linkedinMatch ? linkedinMatch[1].trim() : '';

// Extract X content  
const xMatch = body.match(/## X\/Twitter \(Thread\)\n([\s\S]*?)(?=##|$)/s);
data.x_content = xMatch ? xMatch[1].trim() : '';

// Extract Facebook content
const fbMatch = body.match(/## Facebook\n([\s\S]*?)(?=##|$)/s);
data.facebook_content = fbMatch ? fbMatch[1].trim() : '';

return [{ json: data }];

// Check if post should be published now
const data = $input.first().json;
const now = new Date();

// Parse scheduled time
if (!data.scheduled_date) {
  return [{ json: { ...data, should_publish: false, reason: 'No scheduled date' } }];
}

const scheduledDate = new Date(`${data.scheduled_date}T${data.scheduled_time || '07:00'}`);

// Check if within the last hour (to catch scheduled posts)
const diffHours = (now - scheduledDate) / (1000 * 60 * 60);
const shouldPublish = diffHours >= 0 && diffHours < 1 && data.status === 'draft';

return [{ json: { ...data, should_publish, reason: shouldPublish ? 'Ready to publish' : `Scheduled for ${scheduledDate}, currently ${now}` } }];

// Post to log file for manual review
const data = $input.first().json;

const logEntry = {
  timestamp: new Date().toISOString(),
  post_title: data.title,
  platforms: data.cross_post_to,
  status: 'ready_for_manual_posting',
  linkedin_content: data.linkedin_content.substring(0, 200) + '...',
  x_content: data.x_content.substring(0, 200) + '...',
  facebook_content: data.facebook_content.substring(0, 200) + '...'
};

// Log to file
const fs = require('fs');
const logPath = '/home/workspace/Skills/social-content/publishing-log.json';

let logs = [];
if (fs.existsSync(logPath)) {
  logs = JSON.parse(fs.readFileSync(logPath, 'utf8'));
}

logs.unshift(logEntry);
fs.writeFileSync(logPath, JSON.stringify(logs, null, 2));

return [{ json: { success: true, logged: true, log_path: logPath } }];
